## 5 -12.064101  4.828783  5  Adelie Torgersen   male
## 6  -5.480114  7.486022  6  Adelie Torgersen female

### visualize 
tsne_df |&gt; 
  ggplot(aes(x = tSNE1, y = tSNE2, color = species, shape = sex)) +
  geom_point()+
  theme(legend.position = "bottom")

